def fill_sampling(slice_list, N):
    """Given a list of slices, draw N samples such that each slice contributes as much as possible

    Parameters
    --------------------------
    slice_list : list of Slice
        List of slices
    N : int
        Number of samples to draw
    """
    A = []
    for s in slice_list:
        A.append(len(s.inliers))
    N_max = np.sum(A)
    if N > N_max:
        raise ValueError('Tried to draw {:d} samples from a pool of only {:d} items'.format(N, N_max))
    samples_from = np.zeros((len(A),), dtype='int')
    remaining = N
    while remaining > 0:
        remaining_groups = np.flatnonzero(samples_from - np.array(A))
        if remaining < len(remaining_groups):
            np.random.shuffle(remaining_groups)
            for g in remaining_groups[:remaining]:
                samples_from[g] += 1
        else:
            to_each = max(1, int(remaining / len(remaining_groups)))
            samples_from = np.min(np.vstack((samples_from + to_each, A)), axis=0)
        remaining = int(N - np.sum(samples_from))
    if not remaining == 0:
        raise ValueError('Still {:d} samples left! This is an error in the selection.')
    samples = []
    for s, a, n in zip(slice_list, A, samples_from):
        if a == n:
            samples.append(np.array(s.inliers))
        elif a == 0:
            samples.append(np.arange([]))
        else:
            chosen = np.random.choice(s.inliers, n, replace=False)
            samples.append(np.array(chosen))
    return samples

def ready_argument_list(self, arguments):
    """ready argument list to be passed to the C function

        :param arguments: List of arguments to be passed to the C function.
            The order should match the argument list on the C function.
            Allowed values are numpy.ndarray, and/or numpy.int32, numpy.float32, and so on.
        :type arguments: list(numpy objects)

        :returns: A list of arguments that can be passed to the C function.
        :rtype: list(Argument)
        """
    ctype_args = []
    for _ in arguments:
        ctype_args.append(None)
    for i, arg in enumerate(arguments):
        if not isinstance(arg, (numpy.ndarray, numpy.number)):
            raise TypeError('Argument is not numpy ndarray or numpy scalar %s' % type(arg))
        dtype_str = str(arg.dtype)
        data = arg.copy()
        if isinstance(arg, numpy.ndarray):
            if dtype_str in dtype_map.keys():
                data_ctypes = data.ctypes.data_as(C.POINTER(dtype_map[dtype_str]))
            else:
                raise TypeError('unknown dtype for ndarray')
        elif isinstance(arg, numpy.generic):
            data_ctypes = dtype_map[dtype_str](arg)
        ctype_args[i] = Argument(numpy=data, ctypes=data_ctypes)
    return ctype_args

